# Module with abstract base classes and virtual methods
from types_module import IMeasurable, Priority

@abstract
class Task(IMeasurable):
    title: str
    priority_level: Priority

    def __init__(self, title: str, priority: Priority):
        self.title = title
        self.priority_level = priority

    def get_value(self) -> float:
        return float(self.priority_level)

    @abstract
    def execute(self) -> str

class ConfigurableTask(Task):
    config: str

    def __init__(self, title: str, priority: Priority, config: str):
        super().__init__(title, priority)
        self.config = config

