# Utility module with concrete implementations
from types_module import Dimension, Priority, IMeasurable
from base_classes import Task, ConfigurableTask

class StandardTask(ConfigurableTask):
    description: str

    def __init__(self, title: str, desc: str, priority: Priority, cfg: str):
        super().__init__(title, priority, cfg)
        self.description = desc

    def execute(self) -> str:
        return f"Standard task: {self.title}"

class PriorityProcessor:
    tasks: list[Task]

    def __init__(self):
        self.tasks = []

    def add_task(self, t: Task):
        self.tasks.append(t)

    def get_total_priority(self) -> float:
        total: float = 0.0
        for t in self.tasks:
            total += t.get_value()
        return total

def process_dimension(d: Dimension) -> float:
    return d.area()

def task_runner(t: Task) -> str:
    result: str = t.execute()
    return f"Ran [{t.title}]: {result}"

def get_status(p: Priority) -> str:
    if p == Priority.LOW:
        return "Low priority"
    elif p == Priority.MEDIUM:
        return "Medium priority"
    else:
        return "High priority"
